import json
import math
import os
import struct


def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _mag(v):
    return math.sqrt(_dot(v, v))


def _normalize(v):
    m = _mag(v)
    if m < 1e-12:
        return (0.0, 0.0, 0.0)
    return (v[0] / m, v[1] / m, v[2] / m)


def detect_format(path):
    size = os.path.getsize(path)
    with open(path, 'rb') as f:
        start = f.read(512)
    if size >= 84:
        tri_count = struct.unpack('<I', start[80:84])[0] if len(start) >= 84 else None
        if tri_count is not None and 84 + tri_count * 50 == size:
            return 'binary'
    stripped = start.lstrip()
    if stripped.startswith(b'solid') and b'facet' in start:
        return 'ascii'
    return 'binary'


def parse_ascii(path):
    triangles = []
    issues = []
    with open(path, 'r', errors='replace') as fh:
        lines = fh.readlines()
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                declared = (float(parts[2]), float(parts[3]), float(parts[4]))
            except Exception:
                issues.append('malformed_ascii')
                i += 1
                continue
            i += 1
            if i >= len(lines) or lines[i].strip() != 'outer loop':
                issues.append('malformed_ascii')
                continue
            i += 1
            verts = []
            for _ in range(3):
                if i >= len(lines):
                    break
                vline = lines[i].strip().split()
                if len(vline) != 4 or vline[0] != 'vertex':
                    break
                verts.append((float(vline[1]), float(vline[2]), float(vline[3])))
                i += 1
            if len(verts) != 3:
                issues.append('malformed_ascii')
                continue
            triangles.append((declared, verts))
        else:
            i += 1
    return triangles, issues


def parse_binary(path):
    triangles = []
    issues = []
    with open(path, 'rb') as f:
        data = f.read()
    if len(data) < 84:
        return [], ['malformed_binary']
    tri_count = struct.unpack('<I', data[80:84])[0]
    expected = 84 + tri_count * 50
    if expected != len(data):
        issues.append('malformed_binary')
        tri_count = max(0, (len(data) - 84) // 50)
    off = 84
    for _ in range(tri_count):
        rec = data[off:off+50]
        if len(rec) < 50:
            issues.append('malformed_binary')
            break
        vals = struct.unpack('<12fH', rec)
        declared = (vals[0], vals[1], vals[2])
        verts = [
            (vals[3], vals[4], vals[5]),
            (vals[6], vals[7], vals[8]),
            (vals[9], vals[10], vals[11]),
        ]
        triangles.append((declared, verts))
        off += 50
    return triangles, issues


def classify(path):
    fmt = detect_format(path)
    triangles, parse_issues = parse_ascii(path) if fmt == 'ascii' else parse_binary(path)
    if not triangles:
        return {'file': path, 'valid': False, 'reason': parse_issues[0] if parse_issues else 'no_faces'}

    reasons = []
    if parse_issues:
        reasons.append(parse_issues[0])

    edge_count = {}
    degenerate = False
    inverted = False
    for declared, verts in triangles:
        rounded = [tuple(round(c, 6) for c in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted((rounded[j], rounded[(j + 1) % 3])))
            edge_count[edge] = edge_count.get(edge, 0) + 1
        e1 = _sub(verts[1], verts[0])
        e2 = _sub(verts[2], verts[0])
        n = _cross(e1, e2)
        if _mag(n) < 1e-10:
            degenerate = True
            continue
        dn = _normalize(declared)
        if _mag(dn) > 0:
            if _dot(dn, _normalize(n)) < -0.99:
                inverted = True

    if any(cnt == 1 for cnt in edge_count.values()):
        reasons.append('open_edges')
    if any(cnt > 2 for cnt in edge_count.values()):
        reasons.append('non_manifold_edges')
    if degenerate:
        reasons.append('degenerate_triangles')
    if inverted:
        reasons.append('inverted_normals')

    if reasons:
        return {'file': path, 'valid': False, 'reason': reasons[0]}
    return {'file': path, 'valid': True}


results = []
for i in range(1, 21):
    name = f'supplier_{i:03d}.stl'
    results.append(classify(name))

with open('validation_report.json', 'w') as f:
    json.dump({'results': results}, f)

print(json.dumps({'results': results}, indent=2))

